import SwiftUI
import AuthenticationServices

class SignInWithAppleViewModel: ObservableObject {
    @Published var isSignedIn = false
    @Published var errorMessage: String?
}

struct SignInWithAppleView: View {
    @StateObject private var viewModel = SignInWithAppleViewModel()

    var body: some View {
        VStack(spacing: 16) {
            SignInWithAppleButton(.signIn, onRequest: { request in
                request.requestedScopes = [.fullName, .email]
            }, onCompletion: { result in
                switch result {
                case .success(let authorization):
                    guard let credential = authorization.credential as? ASAuthorizationAppleIDCredential else { return }
                    let userIdentifier = credential.userIdentifier ?? ""
                    // Store userIdentifier in Keychain for persistence across app launches.
                    DispatchQueue.main.async {
                        viewModel.isSignedIn = true
                        viewModel.errorMessage = nil
                    }
                case .failure(let error):
                    DispatchQueue.main.async {
                        if (error as NSError).code == ASAuthorizationError.canceled.rawValue {
                            viewModel.errorMessage = nil
                        } else {
                            viewModel.errorMessage = error.localizedDescription
                        }
                    }
                }
            })
            .signInWithAppleButtonStyle(.black)

            if let message = viewModel.errorMessage {
                Text(message)
                    .font(.caption)
                    .foregroundStyle(.red)
            }
        }
    }
}
